svg.script:
window.addEventListener('load', function() {
  const track = document.getElementById("ElipsTreck");
  if (!track) { console.error("Нет эллипса"); return; }

  const cx = +track.getAttribute("cx");
  const cy = +track.getAttribute("cy");
  const rx = +track.getAttribute("rx");
  const ry = +track.getAttribute("ry");

  const wrappers = [];

  for (let i = 1; i <= 10; i++) {
    const flag = document.getElementById("ffffffffff" + i);
    if (!flag) continue;

    const wrapper = document.createElementNS("http://www.w3.org/2000/svg", "g");
    const bbox = flag.getBBox();
    const centerX = bbox.x + bbox.width / 2;
    const centerY = bbox.y + bbox.height / 2;

    flag.parentNode.replaceChild(wrapper, flag);
    wrapper.appendChild(flag);
    flag.setAttribute("transform", `translate(${-centerX}, ${-centerY})`);

    wrappers.push({ el: wrapper });
  }

  function animate(t) {
    wrappers.forEach((w, i) => {
      const angle = t * 0.0003 + (i / 10) * Math.PI * 2;
      const x = cx + rx * Math.cos(angle);
      const y = cy + ry * Math.sin(angle);

      // Масштаб: минимум на 6 часах (низ), максимум на 12 часах (верх)
      // sin(angle): 1 на 6 часах, -1 на 12 часах
      // Поэтому вычитаем: чем больше sin, тем меньше масштаб
      const baseScale = 1;
      const amplitude = 0.8; // Амплитуда изменения (0.4 = ±40%)
      const scale = baseScale + amplitude * Math.sin(angle);

      w.el.setAttribute("transform", `translate(${x}, ${y}) scale(${scale})`);
    });
    requestAnimationFrame(animate);
  }

  requestAnimationFrame(animate);
});

(function() {
  const CONTAINER = { x: 1248.19, y: 234.61, w: 1000, h: 700 };
  const PHRASES = [
    "Республика Алтай", "Алтайский край", "Иркутская область",
    "Кемеровская область", "Красноярский край", "Новосибирская область","Новосибирск","Кемерово","Новокузнецк","Бийск","Юрга",
    "Омская область", "Томская область", "Республика Тыва", "Республика Хакасия"
  ];

  const NS = "http://www.w3.org/2000/svg";
  const targetGroup = document.getElementById("Text");
  const animatedItems = [];

  function initPhrases() {
    targetGroup.innerHTML = ''; 

    PHRASES.forEach((text) => {
      const group = document.createElementNS(NS, "g");
      const txt = document.createElementNS(NS, "text");
      txt.textContent = text;
      txt.setAttribute("fill", "#ffffff");
      txt.setAttribute("font-family", "Inter, Arial, sans-serif");
      txt.setAttribute("font-size", "100");
      txt.setAttribute("font-weight", "800");
      txt.setAttribute("stroke", "#000023");
      txt.setAttribute("stroke-width", "2");
      txt.setAttribute("text-anchor", "middle");
      txt.setAttribute("dominant-baseline", "central");

      group.appendChild(txt);
      targetGroup.appendChild(group);

      const bbox = txt.getBBox();
      const padX = (bbox.width * 1.0) / 2;
      const padY = (bbox.height * 1.0) / 2;
      const safeMinX = CONTAINER.x + padX;
      const safeMaxX = CONTAINER.x + CONTAINER.w - padX;
      const safeMinY = CONTAINER.y + padY;
      const safeMaxY = CONTAINER.y + CONTAINER.h - padY;
      const cx = safeMinX + Math.random() * (safeMaxX - safeMinX);
      const cy = safeMinY + Math.random() * (safeMaxY - safeMinY);
      const rx = 60 + Math.random() * 140;
      const ry = 40 + Math.random() * 100;
      const speed = 0.0004 + Math.random() * 0.0012;
      const phase = Math.random() * Math.PI * 2;
      const scalePhase = Math.random() * Math.PI * 2;

      animatedItems.push({ 
        el: group, 
        textEl: txt,
        cx, cy, rx, ry, speed, phase, scalePhase 
      });
    });

    requestAnimationFrame(animateLoop);
  }

  function animateLoop(timestamp) {
    animatedItems.forEach((item) => {
      const angle = timestamp * item.speed + item.phase;
      const x = item.cx + item.rx * Math.cos(angle);
      const y = item.cy + item.ry * Math.sin(angle);

      const normalized = (Math.sin(timestamp * item.speed * 0.6 + item.scalePhase) + 1) / 2;
      const scale = 0.2 + normalized * 0.8;

      const minVisibleScale = 0.5;
      if (scale < minVisibleScale) {
        item.textEl.setAttribute("opacity", "0");
        item.el.setAttribute("display", "none");
      } else {
        item.textEl.setAttribute("opacity", "1");
        item.el.setAttribute("display", "block");
      }

      item.el.setAttribute("transform", `translate(${x}, ${y}) scale(${scale})`);
    });

    requestAnimationFrame(animateLoop);
  }

  if (document.fonts && document.fonts.ready) {
    document.fonts.ready.then(initPhrases);
  } else {
    window.addEventListener("load", initPhrases);
  }
})();
